let mailMetni = "";

for (const item of $input.all()) {
  const subject = item.json.subject || "Konu Yok";
  const from = item.json.from || "Bilinmeyen Gönderen";
  const snippet = item.json.snippet || "";

  mailMetni += `Gönderen: ${from}\nKonu: ${subject}\nÖzet İçerik: ${snippet}\n-------------------\n`;
}

return [{ json: { tumMailler: mailMetni } }];
